class Solution:
    def getNoZeroIntegers(self, n: int) -> list:
        def has_zero(x):
            return '0' in str(x)
        for a in range(1, n):
            b = n - a
            if not has_zero(a) and not has_zero(b):
                return [a, b]
        return [-1, -1]

